import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { Helmet } from 'react-helmet-async';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Autoplay, Pagination, Navigation } from 'swiper/modules';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import ProductCard from '../components/ProductCard';
import { unwrapFeaturedResponse, apiMessage } from '../lib/api';

import 'swiper/css';
import 'swiper/css/pagination';
import 'swiper/css/navigation';

const HERO_SLIDES = [
  {
    title: 'New season collection',
    subtitle: 'Curated style & living',
    image:
      'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=1400&auto=format&fit=crop&q=70',
    cta: '/products?cat=fashion'
  },
  {
    title: 'Tech that fits your life',
    subtitle: 'Electronics & audio',
    image:
      'https://images.unsplash.com/photo-1498049794561-7780e7231661?w=1400&auto=format&fit=crop&q=70',
    cta: '/products?cat=electronics'
  },
  {
    title: 'Home refresh',
    subtitle: 'Lighting, décor & more',
    image:
      'https://images.unsplash.com/photo-1586023492125-27b2c045efd7?w=1400&auto=format&fit=crop&q=70',
    cta: '/products?cat=home'
  }
];

const Home = () => {
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [featuredLoading, setFeaturedLoading] = useState(true);
  const [featuredError, setFeaturedError] = useState(null);
  const { addToCart } = useCart();

  useEffect(() => {
    fetchFeaturedProducts();
  }, []);

  const fetchFeaturedProducts = async () => {
    setFeaturedLoading(true);
    setFeaturedError(null);
    try {
      const response = await axios.get('/api/products/featured');
      const list = unwrapFeaturedResponse(response);
      setFeaturedProducts(list.slice(0, 8));
    } catch (error) {
      console.error('Error fetching products:', error);
      const msg =
        error.code === 'ERR_NETWORK' || error.message?.includes('Network Error')
          ? 'Cannot reach the API. Start the backend on port 5000.'
          : apiMessage(error, 'Failed to load products');
      setFeaturedError(msg);
      setFeaturedProducts([]);
    } finally {
      setFeaturedLoading(false);
    }
  };

  const handleAddToCart = async (product) => {
    const result = await addToCart(product, 1);
    if (result.success) toast.success(`${product.name} added to cart`);
    else toast.error(result.error || 'Could not add to cart');
  };

  return (
    <>
      <Helmet>
        <title>Nova Shop — Premium style & living</title>
        <meta
          name="description"
          content="Nova Shop — curated products across electronics, fashion, home, beauty and sports."
        />
      </Helmet>

      <section className="hero hero-swiper" aria-label="Hero banner">
        <Swiper
          modules={[Autoplay, Pagination, Navigation]}
          autoplay={{ delay: 5500, disableOnInteraction: false }}
          pagination={{ clickable: true }}
          navigation
          loop
          className="hero-swiper-inner"
        >
          {HERO_SLIDES.map((slide, i) => (
            <SwiperSlide key={i}>
              <div className="hero-slide">
                <div
                  className="hero-slide__bg"
                  style={{ backgroundImage: `url(${slide.image})` }}
                  aria-hidden
                />
                <div className="hero-content container hero-slide__content">
                  <div className="hero-badge">✦ Nova Shop</div>
                  <h1>{slide.title}</h1>
                  <p>{slide.subtitle}</p>
                  <Link to={slide.cta} className="btn btn-primary">
                    Shop now ›
                  </Link>
                </div>
              </div>
            </SwiperSlide>
          ))}
        </Swiper>
      </section>

      <section className="section bg-cream" id="categories" aria-label="Shop categories">
        <div className="container">
          <div className="section-header text-center">
            <span className="section-tag">Browse by category</span>
            <h2>What are you looking for?</h2>
          </div>
          <div className="categories-grid">
            <Link to="/products?cat=electronics" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">📱</span>
              <span>Electronics</span>
            </Link>
            <Link to="/products?cat=fashion" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">👗</span>
              <span>Fashion</span>
            </Link>
            <Link to="/products?cat=home" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">🏡</span>
              <span>Home</span>
            </Link>
            <Link to="/products?cat=beauty" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">💄</span>
              <span>Beauty</span>
            </Link>
            <Link to="/products?cat=sports" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">⚽</span>
              <span>Sports</span>
            </Link>
          </div>
        </div>
      </section>

      <section className="section" id="featured" aria-label="Featured products">
        <div className="container">
          <div className="section-header section-header-flex">
            <div>
              <span className="section-tag">Handpicked for you</span>
              <h2>Featured products</h2>
            </div>
            <Link to="/products" className="btn btn-outline btn-sm">
              View all ›
            </Link>
          </div>
          {featuredLoading ? (
            <p style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
              Loading featured products…
            </p>
          ) : featuredError ? (
            <div className="api-error-banner" role="alert">
              <p>
                <strong>Featured products could not be loaded.</strong> {featuredError}
              </p>
              <button type="button" className="btn btn-outline btn-sm" onClick={fetchFeaturedProducts}>
                Retry
              </button>
            </div>
          ) : featuredProducts.length === 0 ? (
            <p className="empty-products-hint empty-products-hint--muted" style={{ textAlign: 'center' }}>
              No featured products yet. Seed the database from the backend (
              <code>node scripts/seedDatabase.js</code>).
            </p>
          ) : (
            <div className="products-grid">
              {featuredProducts.map((product) => (
                <ProductCard key={product._id} product={product} onAddToCart={handleAddToCart} />
              ))}
            </div>
          )}
        </div>
      </section>

      <section className="promo-banner" aria-label="Promotional offer">
        <div className="container promo-content">
          <span className="section-tag section-tag-gold">Limited time</span>
          <h2>20% off your first order</h2>
          <p>
            Use code <strong>NOVA20</strong> at checkout, or <strong>SAVE10</strong> for £10 off.
          </p>
          <div className="promo-code">
            <span>NOVA20</span>
            <button
              type="button"
              className="copy-btn"
              onClick={() => {
                navigator.clipboard.writeText('NOVA20');
                toast.success('Code copied');
              }}
            >
              Copy
            </button>
          </div>
          <Link to="/products" className="btn btn-gold">
            Shop the sale ›
          </Link>
        </div>
      </section>

      <section className="section bg-cream" aria-label="Why choose us">
        <div className="container">
          <div className="section-header text-center">
            <span className="section-tag">Why Nova Shop</span>
            <h2>Shopping made simple</h2>
          </div>
          <div className="trust-grid">
            <div className="trust-card">
              <div className="trust-card__icon">🚚</div>
              <h4>Free delivery</h4>
              <p>On orders over £50. Express options at checkout.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">🔒</div>
              <h4>Secure payments</h4>
              <p>Stripe-powered checkout with modern card support.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">↩️</div>
              <h4>Easy returns</h4>
              <p>30-day hassle-free returns on qualifying items.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">💬</div>
              <h4>Support</h4>
              <p>We are here to help via email and chat.</p>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default Home;
